    "active" => [
        ["algo" => 696, "uuid" => "533944", "name" => "x509v3", "type" => "pki", "status" => "active", "title" => "X.509 v3", "description_md" => "X.509 v3 is the standard format for public key certificates used in TLS/SSL, code signing, email (S/MIME), and all PKI systems. Defined in RFC 5280.\n\nX.509 v3 adds extensions (SANs, key usage, basic constraints, CRL/OCSP pointers) to the base v1/v2 certificate format. The 'v3' in virtually every TLS certificate refers to this format.", "mental_model" => "The universal PKI certificate -- X.509 v3 RFC 5280, TLS/code-signing/email standard.", "purpose" => ["public key certificate for tls/pki/smime"], "good_for" => ["tls server certs", "code signing certs", "email s/mime", "client auth certs", "ca certificates"], "avoid_for" => ["non-pki trust (ssh uses pubkey directly)"], "pros" => ["universal standard", "rich extensions", "rfc 5280", "openssl/java/windows native"], "cons" => ["complex format", "revocation challenges"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Cert signature quantum-vulnerable (ECDSA/RSA). PQ certs under NIST development.", "post_quantum_status" => 2, "example" => ["scenario" => "TLS server certificate", "input" => ["subject" => "CN=example.com", "pubkey" => "EC P-256", "san" => "example.com"], "output" => ["cert" => "x509v3 DER certificate"]], "flow" => ["CA signs: tbsCertificate + signatureAlgorithm + signature", "extensions: SAN, keyUsage, basicConstraints, AIA, CDP", "browser validates chain to trusted root"], "related" => ["crl", "ocsp", "csr", "ct", "acme"]],
        ["algo" => 698, "uuid" => "ac9e23", "name" => "crl", "type" => "pki", "status" => "active", "title" => "CRL", "description_md" => "CRL (Certificate Revocation List, RFC 5280) is a CA-signed list of revoked certificate serial numbers. Clients download the CRL to check if a certificate has been revoked.\n\nCRLs are still mandatory for many PKI deployments. OCSP is the online alternative but CRLs remain the baseline revocation mechanism.", "mental_model" => "Batch revocation list -- CRL, CA-signed serial numbers, download and check.", "purpose" => ["batch certificate revocation"], "good_for" => ["enterprise pki revocation", "code signing revocation", "s/mime revocation"], "avoid_for" => ["real-time check (ocsp stapling faster)"], "pros" => ["rfc 5280 standard", "offline capable", "universal pki support"], "cons" => ["can be large", "not real-time"], "difficulty" => 2, "security" => 4, "quantum_impact" => "CRL signed with CA key; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Enterprise PKI CRL check", "input" => ["cert" => "end-entity cert", "cdp" => "CRL URL"], "output" => ["revoked" => "false"]], "flow" => ["download CRL from CDP", "verify CRL signature", "check serial not in list"], "related" => ["x509v3", "ocsp", "cdp", "ocsp-stapling"]],
        ["algo" => 699, "uuid" => "512fe5", "name" => "ocsp", "type" => "pki", "status" => "active", "title" => "OCSP", "description_md" => "OCSP (Online Certificate Status Protocol, RFC 6960) provides real-time certificate revocation checking. A client sends a signed request to an OCSP responder and gets a signed response indicating good/revoked/unknown.\n\nOCSP Stapling eliminates the privacy and latency concerns of direct OCSP checks.", "mental_model" => "Real-time revocation check -- OCSP RFC 6960, single-cert online status.", "purpose" => ["real-time certificate revocation checking"], "good_for" => ["tls revocation", "real-time cert status", "single cert query"], "avoid_for" => ["privacy concerns (ocsp-stapling better)"], "pros" => ["real-time", "rfc 6960 standard", "single cert query"], "cons" => ["privacy leak to CA", "latency", "responder availability"], "difficulty" => 2, "security" => 4, "quantum_impact" => "OCSP response signed RSA/ECDSA; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS OCSP revocation check", "input" => ["cert_serial" => "serial", "ocsp_url" => "responder URL"], "output" => ["status" => "good/revoked"]], "flow" => ["OCSP request (certId)", "responder: signed response", "client: verify + cache"], "related" => ["crl", "ocsp-stapling", "x509v3", "aia"]],
        ["algo" => 700, "uuid" => "d825a4", "name" => "ocsp-stapling", "type" => "pki", "status" => "active", "title" => "OCSP Stapling", "description_md" => "OCSP Stapling (RFC 6066 TLS extension) allows the TLS server to include a pre-fetched OCSP response in the TLS handshake, eliminating the client privacy leak and latency of direct OCSP queries.\n\nOCSP Stapling is the best practice for TLS revocation. The server fetches and caches the OCSP response and staples it to the TLS handshake.", "mental_model" => "Server-side OCSP cached in TLS handshake -- no client OCSP queries, best practice.", "purpose" => ["privacy-preserving tls revocation via stapling"], "good_for" => ["modern tls revocation", "high-traffic servers", "privacy revocation"], "avoid_for" => ["servers that cannot reach OCSP (use CRL)"], "pros" => ["no client privacy leak", "no client latency", "rfc 6066", "server caches response"], "cons" => ["server must refresh", "not instantaneous revocation"], "difficulty" => 1, "security" => 4, "quantum_impact" => "OCSP response signature; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "HTTPS server OCSP Stapling", "input" => ["stapled_response" => "pre-fetched OCSP"], "output" => ["client" => "cert status confirmed without OCSP query"]], "flow" => ["server pre-fetches OCSP", "includes in TLS CertificateStatus", "client verifies without direct OCSP query"], "related" => ["ocsp", "crl", "x509v3", "tls-features"]],
        ["algo" => 701, "uuid" => "832b97", "name" => "csr", "type" => "pki", "status" => "active", "title" => "CSR", "description_md" => "CSR (Certificate Signing Request, PKCS#10 / RFC 2986) is the format used to request a certificate from a CA. Contains the public key, subject name, and extensions, signed by the applicant's private key.\n\nCSRs are the standard way to request TLS certificates. openssl req generates CSRs; CAs sign them to produce X.509 certificates.", "mental_model" => "Certificate request to CA -- CSR PKCS#10, public key + subject + self-signature.", "purpose" => ["certificate request to ca"], "good_for" => ["tls cert issuance", "code signing request", "enterprise pki enrollment"], "avoid_for" => ["automated (acme handles internally)"], "pros" => ["universal standard", "pkcs#10 rfc 2986", "private key never leaves requester"], "cons" => ["manual workflow without acme"], "difficulty" => 1, "security" => 4, "quantum_impact" => "CSR signed with applicant key; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS certificate CSR", "input" => ["privkey" => "EC P-256", "cn" => "example.com", "san" => "DNS:example.com"], "output" => ["csr" => "PEM PKCS#10"]], "flow" => ["generate keypair", "CertificationRequestInfo (subject + pubkey)", "sign with private key"], "related" => ["x509v3", "acme", "est", "scep"]],
        ["algo" => 702, "uuid" => "8ae9df", "name" => "cms", "type" => "pki", "status" => "active", "title" => "CMS", "description_md" => "CMS (Cryptographic Message Syntax, RFC 5652) is the IETF successor to PKCS#7. Defines formats for signed data, enveloped data, digested data using X.509 certificates.\n\nCMS is used in S/MIME email, Authenticode code signing, and PKCS#12. The CAdES format extends CMS for long-term signatures.", "mental_model" => "Signed/encrypted PKI container -- CMS RFC 5652, PKCS#7 successor, S/MIME basis.", "purpose" => ["signed/encrypted data containers (pki)"], "good_for" => ["s/mime email", "authenticode code signing", "pkcs#12 containers"], "avoid_for" => ["jwt/jws (web-native)", "simple signing (minisign)"], "pros" => ["rfc 5652 standard", "s/mime standard", "versatile sign/encrypt/both"], "cons" => ["complex asn.1", "heavy for web use"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Signed RSA/ECDSA; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "S/MIME email signing", "input" => ["email" => "message", "cert" => "sender cert"], "output" => ["signed_email" => "CMS SignedData"]], "flow" => ["digest content", "sign with signer key", "CMS SignedData: content+cert+sig"], "related" => ["x509v3", "csr", "cades", "pkcs11"]],
        ["algo" => 703, "uuid" => "fb31a2", "name" => "scep", "type" => "pki", "status" => "active", "title" => "SCEP", "description_md" => "SCEP (Simple Certificate Enrollment Protocol, RFC 8894) is a protocol for automated certificate enrollment using HTTP and PKCS#7/CMS. Widely used in network device PKI (routers, switches, VPN gateways, MDM).\n\nSCEP is the de facto standard for network device certificate enrollment. RFC 8894 modernized the original Cisco draft.", "mental_model" => "Network device cert enrollment -- SCEP RFC 8894, HTTP-based, Cisco/MDM standard.", "purpose" => ["automated cert enrollment (network devices/mdm)"], "good_for" => ["cisco ios cert enrollment", "mdm mobile certs", "network device pki"], "avoid_for" => ["web servers (acme)", "new deployments (est preferred)"], "pros" => ["rfc 8894", "cisco/juniper standard", "mdm deployed"], "cons" => ["older design", "est is modern replacement"], "difficulty" => 2, "security" => 3, "quantum_impact" => "CMS/RSA based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Cisco IOS cert enrollment", "input" => ["csr" => "device csr", "ca_url" => "scep url"], "output" => ["cert" => "device x509v3 cert"]], "flow" => ["GetCACert", "PKCSReq: CMS-wrapped CSR", "CertRep: signed cert"], "related" => ["est", "acme", "csr", "cms"]],
        ["algo" => 704, "uuid" => "e85be4", "name" => "est", "type" => "pki", "status" => "active", "title" => "EST", "description_md" => "EST (Enrollment over Secure Transport, RFC 7030) is the modern replacement for SCEP using HTTPS and CMS. Supports re-enrollment, server-side keygen, and CSR attributes.\n\nEST uses HTTPS with mutual TLS or HTTP auth. Preferred over SCEP for new network device and IoT PKI deployments.", "mental_model" => "Modern SCEP replacement -- EST RFC 7030, HTTPS-based cert enrollment.", "purpose" => ["modern https cert enrollment"], "good_for" => ["modern network device pki", "iot cert enrollment", "scep migration"], "avoid_for" => ["public web certs (acme)", "legacy cisco (scep required)"], "pros" => ["rfc 7030", "https secure", "modern scep replacement", "optional server-side keygen"], "cons" => ["less deployed than scep in legacy devices"], "difficulty" => 2, "security" => 4, "quantum_impact" => "TLS/RSA based; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "EST IoT device enrollment", "input" => ["csr" => "device csr", "url" => "https://ca/.well-known/est"], "output" => ["cert" => "enrolled cert"]], "flow" => ["HTTPS POST /simpleenroll with CSR", "CA returns PKCS#7 cert"], "related" => ["scep", "acme", "csr", "cms"]],
        ["algo" => 705, "uuid" => "cab10e", "name" => "acme", "type" => "pki", "status" => "active", "title" => "ACME", "description_md" => "ACME (Automatic Certificate Management Environment, RFC 8555) is the protocol powering Let's Encrypt. Automates domain validation (DV) and certificate issuance/renewal via HTTP-01 or DNS-01 challenges.\n\nACME revolutionized TLS certificate issuance. Let's Encrypt issues billions of free DV certificates. Certbot, acme.sh, and Caddy use ACME natively.", "mental_model" => "Let's Encrypt protocol -- ACME RFC 8555, automated DV cert issuance/renewal.", "purpose" => ["automated tls cert issuance/renewal"], "good_for" => ["lets encrypt tls certs", "automated cert renewal", "web server tls automation"], "avoid_for" => ["enterprise pki (est/scep)", "ev/ov certs (manual)", "iot (est)"], "pros" => ["lets encrypt standard", "free dv certs", "fully automated", "rfc 8555", "certbot/caddy standard"], "cons" => ["dv only", "requires domain ownership proof"], "difficulty" => 1, "security" => 4, "quantum_impact" => "ECDSA/RSA account key; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Let's Encrypt cert issuance", "input" => ["domain" => "example.com", "challenge" => "http-01"], "output" => ["cert" => "90-day DV certificate"]], "flow" => ["create acme account", "order cert", "complete http-01 or dns-01 challenge", "submit csr -> get cert"], "related" => ["x509v3", "csr", "est", "ct"]],
        ["algo" => 706, "uuid" => "8c16eb", "name" => "ct", "type" => "pki", "status" => "active", "title" => "Certificate Transparency", "description_md" => "Certificate Transparency (CT, RFC 9162) is a system of public append-only logs where all publicly-trusted TLS certificates must be logged. Browsers require SCTs in certificates.\n\nCT enables detection of misissued certificates. Chrome requires 2+ SCTs. Let's Encrypt automatically submits to CT logs.", "mental_model" => "Public cert audit log -- CT RFC 9162, SCTs, Chrome mandatory, misissuance detection.", "purpose" => ["auditable public log of all tls certificates"], "good_for" => ["tls misissuance detection", "cert monitoring", "chrome compliance"], "avoid_for" => ["private CAs (internal pki exempted)"], "pros" => ["rfc 9162", "chrome mandatory", "misissuance detection", "public auditability"], "cons" => ["exposes cert to public log", "log operator trust required"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Log tree SHA-256; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "CT SCT inclusion", "input" => ["precert" => "pre-certificate", "log" => "Google Argon"], "output" => ["sct" => "signed certificate timestamp"]], "flow" => ["CA submits precert to CT log", "log returns SCT", "CA embeds SCT in cert", "browser verifies SCT"], "related" => ["x509v3", "sct", "precert-poison", "acme"]],
        ["algo" => 707, "uuid" => "048868", "name" => "mft", "type" => "pki", "status" => "active", "title" => "RPKI Manifest", "description_md" => "RPKI Manifest (RFC 9286) is a signed list of all objects that a CA publishes in its RPKI repository. Detects missing or added objects via authenticated enumeration.\n\nRPKI Manifests ensure all published objects are accounted for and haven't been removed by attackers.", "mental_model" => "RPKI signed file list -- Manifest RFC 9286, detects missing RPKI objects.", "purpose" => ["rpki repository authenticated enumeration"], "good_for" => ["rpki deployment", "bgp origin validation infrastructure"], "avoid_for" => ["non-rpki contexts"], "pros" => ["rpki standard", "detects missing objects", "rfc 9286"], "cons" => ["rpki-specific", "complex deployment"], "difficulty" => 3, "security" => 4, "quantum_impact" => "RPKI ECDSA/RSA; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "RPKI CA manifest", "input" => ["objects" => ["roa1.roa", "crl.crl"]], "output" => ["manifest" => "signed mft"]], "flow" => ["list repository objects with hashes", "sign as CMS SignedData", "publish in repository"], "related" => ["roa", "tal", "x509v3", "crl"]],
        ["algo" => 708, "uuid" => "3be45c", "name" => "roa", "type" => "pki", "status" => "active", "title" => "ROA", "description_md" => "ROA (Route Origin Authorization, RFC 6482) is a cryptographically signed RPKI object authorizing a specific AS to originate an IP prefix. Prevents BGP hijacking.\n\nROAs are the core of RPKI-based BGP origin validation. ISPs and CDNs deploy ROAs to protect their IP prefixes.", "mental_model" => "BGP hijacking prevention -- ROA RFC 6482, RPKI signs IP prefix to AS mapping.", "purpose" => ["rpki bgp origin authorization"], "good_for" => ["bgp hijacking prevention", "rpki deployment", "ip prefix protection"], "avoid_for" => ["non-bgp routing"], "pros" => ["bgp hijacking prevention", "rfc 6482", "cloudflare/arin deployed"], "cons" => ["rpki infrastructure required"], "difficulty" => 2, "security" => 4, "quantum_impact" => "RPKI signed; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Cloudflare ROA for 1.1.1.0/24", "input" => ["prefix" => "1.1.1.0/24", "asn" => "13335"], "output" => ["roa" => "signed ROA"]], "flow" => ["specify prefix+AS+maxLen", "sign as RPKI CMS", "publish in repository", "routers validate BGP"], "related" => ["mft", "tal", "x509v3"]],
        ["algo" => 709, "uuid" => "3bbdba", "name" => "tal", "type" => "pki", "status" => "active", "title" => "TAL", "description_md" => "TAL (Trust Anchor Locator, RFC 8630) is a file containing the URI and public key hash of an RPKI Trust Anchor. Validators use TALs to bootstrap trust for RPKI validation.\n\nThe 5 RIRs (ARIN, RIPE, APNIC, LACNIC, AFRINIC) each publish a TAL. RPKI validators ship with these TALs.", "mental_model" => "RPKI trust anchor bootstrap -- TAL RFC 8630, RIR root of trust for BGP validation.", "purpose" => ["rpki trust anchor bootstrap"], "good_for" => ["rpki validator configuration", "bgp validation bootstrap"], "avoid_for" => ["non-rpki contexts"], "pros" => ["rfc 8630", "rir standard", "simple format"], "cons" => ["rpki-specific"], "difficulty" => 1, "security" => 4, "quantum_impact" => "TAL key hash; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "RPKI validator TAL init", "input" => ["tal" => "arin.tal (URI+pubkey)"], "output" => ["root" => "RPKI trust anchor"]], "flow" => ["fetch TA cert from TAL URI", "verify against key hash", "use as RPKI root"], "related" => ["roa", "mft", "x509v3"]],
