        ["algo" => 711, "uuid" => "8817e0", "name" => "ipaddress", "type" => "pki", "status" => "active", "title" => "IP Address SAN", "description_md" => "IPAddress is an X.509 SAN type for IP addresses. Required when a TLS certificate must cover an IP address (e.g., internal servers without DNS).\n\nBrowsers require IP SANs for IP-based TLS. Used in internal infrastructure and Kubernetes API server certificates.", "mental_model" => "IP address in TLS cert SAN -- required for IP TLS, no CN workaround.", "purpose" => ["ip address san in x.509 tls certs"], "good_for" => ["internal server ip tls", "kubernetes apiserver certs"], "avoid_for" => ["domain names (use dnsname san)"], "pros" => ["ip tls standard", "rfc 5280", "kubernetes cert standard"], "cons" => ["ip changes invalidate cert"], "difficulty" => 1, "security" => 4, "quantum_impact" => "X.509 extension; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Internal server IP TLS cert", "input" => ["ip" => "10.0.0.1"], "output" => ["san" => "iPAddress: 10.0.0.1"]], "flow" => ["include iPAddress in SAN", "TLS validates against connection IP"], "related" => ["subjectaltname", "x509v3"]],
        ["algo" => 712, "uuid" => "26edba", "name" => "subjectaltname", "type" => "pki", "status" => "active", "title" => "Subject Alternative Name", "description_md" => "Subject Alternative Name (SAN, RFC 5280) specifies the identities a certificate is valid for: DNS names, IP addresses, email addresses, URIs.\n\nBrowsers use SAN (not CN) for TLS validation since Chrome 58. Multi-SAN certs cover multiple domains. Wildcard SANs cover subdomains.", "mental_model" => "TLS domain identity extension -- SAN replaces CN, multi-domain/wildcard support.", "purpose" => ["x.509 certificate identity binding"], "good_for" => ["tls domain validation", "multi-domain certs", "wildcard certs"], "avoid_for" => ["CN-only (deprecated for TLS)"], "pros" => ["rfc 5280", "chrome standard", "multi-domain", "wildcard support"], "cons" => ["wildcard not second-level subdomains"], "difficulty" => 1, "security" => 4, "quantum_impact" => "X.509 extension; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Multi-domain TLS cert", "input" => ["domains" => ["example.com", "www.example.com"]], "output" => ["san" => "DNS:example.com, DNS:www.example.com"]], "flow" => ["include all SANs", "TLS validates against SAN list"], "related" => ["x509v3", "rfc822name", "ipaddress", "acme"]],
        ["algo" => 713, "uuid" => "7d6d74", "name" => "authoritykeyid", "type" => "pki", "status" => "active", "title" => "Authority Key Identifier", "description_md" => "Authority Key Identifier (AKI, RFC 5280) identifies the CA key that signed the certificate. Allows chain building when a CA has multiple keys.\n\nAKI helps TLS chain building match issuer certificates during key rollover.", "mental_model" => "CA key ID in cert -- AKI RFC 5280, chain building + key rollover.", "purpose" => ["ca key identification for chain building"], "good_for" => ["tls chain building", "ca key rollover"], "avoid_for" => ["standalone (required by RFC 5280)"], "pros" => ["rfc 5280 required", "chain building", "key rollover support"], "cons" => ["informational only"], "difficulty" => 1, "security" => 3, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS chain building with AKI", "input" => ["aki" => "key id of signing CA"], "output" => ["chain" => "matched CA cert"]], "flow" => ["AKI = hash of CA pubkey", "chain builder: find issuer where SKI=AKI"], "related" => ["subjectkeyid", "x509v3", "crl"]],
        ["algo" => 714, "uuid" => "3ff68b", "name" => "subjectkeyid", "type" => "pki", "status" => "active", "title" => "Subject Key Identifier", "description_md" => "Subject Key Identifier (SKI, RFC 5280) is a hash of the certificate's public key. Used to identify the key across renewals and pairs with AKI for chain building.\n\nCA certificates must include SKI. Issued certificates set their AKI to match the CA cert's SKI.", "mental_model" => "Cert pubkey hash identifier -- SKI RFC 5280, chain building + key tracking.", "purpose" => ["public key identifier in x.509 certs"], "good_for" => ["tls chain building", "ca cert key tracking", "aki/ski pair"], "avoid_for" => ["standalone (required in CA certs)"], "pros" => ["rfc 5280 required for CA", "chain building"], "cons" => ["informational extension"], "difficulty" => 1, "security" => 3, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "CA cert SKI", "input" => ["ca_pubkey" => "EC P-384"], "output" => ["ski" => "SHA-1 of pubkey"]], "flow" => ["SKI = SHA-1(subjectPublicKey)", "issued certs AKI = this SKI"], "related" => ["authoritykeyid", "x509v3", "crl"]],
        ["algo" => 715, "uuid" => "468442", "name" => "keyusage", "type" => "pki", "status" => "active", "title" => "Key Usage", "description_md" => "Key Usage (RFC 5280) is a critical X.509 extension defining cryptographic operations the key may be used for: digitalSignature, keyEncipherment, keyCertSign, cRLSign, etc.\n\nKey Usage must be critical. TLS leaf certs have digitalSignature; CA certs have keyCertSign + cRLSign.", "mental_model" => "Cert key operation restrictions -- Key Usage, critical RFC 5280, enforces key purpose.", "purpose" => ["restrict cert key usage purposes"], "good_for" => ["tls cert key purpose enforcement", "ca signing restriction"], "avoid_for" => ["non-X.509 key restrictions"], "pros" => ["rfc 5280", "critical enforcement", "misuse prevention"], "cons" => ["must be set correctly or cert rejected"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS server cert key usage", "input" => ["usage" => "digitalSignature, keyAgreement"], "output" => ["keyUsage" => "critical"]], "flow" => ["set bits for cert purpose", "critical: TLS libs enforce"], "related" => ["extendedkeyusage", "basicconstraints", "x509v3"]],
        ["algo" => 716, "uuid" => "900b15", "name" => "extendedkeyusage", "type" => "pki", "status" => "active", "title" => "Extended Key Usage", "description_md" => "Extended Key Usage (EKU, RFC 5280) further restricts certificate purpose via OIDs: serverAuth (TLS), clientAuth, codeSigning, emailProtection, timeStamping.\n\nTLS server certs need id-kp-serverAuth; code signing certs need id-kp-codeSigning. Combined with Key Usage.", "mental_model" => "Fine-grained cert purpose via OIDs -- EKU, TLS/code-signing/email standard.", "purpose" => ["fine-grained cert purpose restriction (oid-based)"], "good_for" => ["tls server (serverauth)", "code signing", "email (emailprotection)", "timestamp"], "avoid_for" => ["CA certs (use keyUsage keyCertSign)"], "pros" => ["rfc 5280", "oid-based purpose", "tls standard"], "cons" => ["OID knowledge required"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS server cert EKU", "input" => ["eku" => "id-kp-serverAuth"], "output" => ["extKeyUsage" => "TLS Web Server Auth"]], "flow" => ["include EKU OID for cert type", "TLS requires serverAuth OID"], "related" => ["keyusage", "basicconstraints", "x509v3"]],
        ["algo" => 717, "uuid" => "ec5be2", "name" => "basicconstraints", "type" => "pki", "status" => "active", "title" => "Basic Constraints", "description_md" => "Basic Constraints (RFC 5280) is a critical extension identifying if the certificate is a CA. The cA boolean and pathLenConstraint limit CA depth in chains.\n\nBasicConstraints cA=TRUE marks a CA certificate. PathLen=0 means the CA can only issue end-entity certs.", "mental_model" => "CA flag + chain depth limit -- BasicConstraints, critical, CA cert required.", "purpose" => ["ca flag and chain depth in x.509"], "good_for" => ["CA cert marking", "path length enforcement"], "avoid_for" => ["end-entity (cA=FALSE default)"], "pros" => ["rfc 5280 critical", "ca chain depth control"], "cons" => ["must be correct or chain building fails"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "Intermediate CA cert", "input" => ["ca" => true, "pathLen" => 0], "output" => ["basicConstraints" => "critical, CA:TRUE, pathLen:0"]], "flow" => ["cA=TRUE + pathLen for CA certs", "end-entity certs: cA=FALSE"], "related" => ["keyusage", "x509v3", "authoritykeyid"]],
        ["algo" => 718, "uuid" => "a5aeee", "name" => "nameconstraints", "type" => "pki", "status" => "active", "title" => "Name Constraints", "description_md" => "Name Constraints (RFC 5280) restricts what DNS names, IPs, or email addresses a CA may issue certificates for. Used in technically constrained subordinate CAs.\n\nName Constraints permits browsers to trust a constrained sub-CA only for specific domains.", "mental_model" => "CA issuance domain restriction -- NameConstraints, permitted/excluded subtrees.", "purpose" => ["restrict ca to specific domains/ips"], "good_for" => ["technically constrained sub-CA", "enterprise private CA domain restriction"], "avoid_for" => ["end-entity certs"], "pros" => ["rfc 5280", "constrained CA trust", "enterprise CA restriction"], "cons" => ["complex to implement correctly"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "Enterprise constrained sub-CA", "input" => ["permitted" => ".example.com"], "output" => ["nameConstraints" => "permitted: .example.com"]], "flow" => ["set permittedSubtrees and/or excludedSubtrees", "browsers enforce on issued certs"], "related" => ["basicconstraints", "x509v3", "subjectaltname"]],
        ["algo" => 719, "uuid" => "f5afc0", "name" => "cdp", "type" => "pki", "status" => "active", "title" => "CRL Distribution Points", "description_md" => "CRL Distribution Points (CDP, RFC 5280) specifies URLs where a certificate's CRL can be downloaded. Enables revocation checking via CRL.\n\nCDP URIs are embedded in end-entity certs by CAs. Clients download the CRL and check revocation.", "mental_model" => "Where to get CRL -- CDP extension, URL in cert for CRL download.", "purpose" => ["crl location in x.509 cert"], "good_for" => ["enterprise pki crl pointing", "code signing revocation"], "avoid_for" => ["public TLS (OCSP stapling preferred)"], "pros" => ["rfc 5280", "offline capable revocation"], "cons" => ["CRL download overhead"], "difficulty" => 1, "security" => 3, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "Enterprise cert CRL pointer", "input" => ["cdp_url" => "http://ca/crl.crl"], "output" => ["cRLDistributionPoints" => "http://ca/crl.crl"]], "flow" => ["client downloads CRL from CDP URI", "checks serial against CRL"], "related" => ["crl", "aia", "x509v3"]],
        ["algo" => 720, "uuid" => "d8e382", "name" => "aia", "type" => "pki", "status" => "active", "title" => "Authority Information Access", "description_md" => "Authority Information Access (AIA, RFC 5280) provides two pointers in an X.509 cert: OCSP responder URL (for revocation) and CA Issuer URL (for chain building).\n\nAIA-OCSP allows clients to check revocation. AIA-caIssuers allows clients to fetch intermediate CA certs for chain building.", "mental_model" => "OCSP URL + issuer cert URL in cert -- AIA, chain building + revocation pointer.", "purpose" => ["ocsp url + issuer cert url in x.509"], "good_for" => ["tls ocsp revocation pointer", "chain building"], "avoid_for" => ["standalone"], "pros" => ["rfc 5280", "ocsp + chain building"], "cons" => ["informational; depends on OCSP availability"], "difficulty" => 1, "security" => 3, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS cert AIA", "input" => ["ocsp" => "http://ocsp.ca/", "issuer" => "http://ca/ca.crt"], "output" => ["aia" => "OCSP URL + Issuer URL"]], "flow" => ["client reads AIA OCSP URL for revocation", "reads caIssuers URL for intermediate"], "related" => ["ocsp", "crl", "cdp", "x509v3"]],
        ["algo" => 721, "uuid" => "4a5fc5", "name" => "ocsp-nocheck", "type" => "pki", "status" => "active", "title" => "OCSP No-Check", "description_md" => "OCSP No-Check (RFC 6960) is an extension that tells clients not to check revocation of the OCSP responder certificate itself, avoiding recursive revocation loops.\n\nOCSP responder certs include id-pkix-ocsp-nocheck to prevent infinite regress during OCSP validation.", "mental_model" => "OCSP responder cert -- no-check extension prevents revocation loop.", "purpose" => ["prevent recursive ocsp revocation check"], "good_for" => ["ocsp responder certs only"], "avoid_for" => ["end-entity or CA certs"], "pros" => ["rfc 6960", "prevents loop"], "cons" => ["specific to OCSP responder certs only"], "difficulty" => 1, "security" => 3, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "OCSP responder cert", "input" => ["cert" => "ocsp-responder.crt"], "output" => ["ocspNoCheck" => "included"]], "flow" => ["include id-pkix-ocsp-nocheck in OCSP responder cert"], "related" => ["ocsp", "x509v3", "aia"]],
        ["algo" => 722, "uuid" => "d5a986", "name" => "precert-poison", "type" => "pki", "status" => "active", "title" => "Precertificate Poison", "description_md" => "Precertificate Poison (RFC 6962) is a critical extension in CT precertificates that prevents them from being used as actual TLS certificates. CAs submit precerts to CT logs, get SCTs, then issue the real cert without the poison.\n\nThe poison extension ensures precerts are not accepted as real certs by TLS clients.", "mental_model" => "CT precert marker -- poison extension, prevents precert use as real cert.", "purpose" => ["ct precertificate (non-usable marker)"], "good_for" => ["ct log submission precerts only"], "avoid_for" => ["real certificates"], "pros" => ["rfc 6962", "ct precert standard"], "cons" => ["single-purpose extension"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "CT precert submission", "input" => ["cert" => "precert with poison"], "output" => ["log" => "SCT returned"]], "flow" => ["CA creates precert (poison ext)", "submits to CT logs", "gets SCTs", "issues real cert (sans poison, with SCTs)"], "related" => ["sct", "ct", "x509v3"]],
        ["algo" => 723, "uuid" => "0b803c", "name" => "sct", "type" => "pki", "status" => "active", "title" => "SCT", "description_md" => "SCT (Signed Certificate Timestamp, RFC 6962) is a signed promise from a CT log that a certificate or precert was logged. Embedded in certificates or delivered via TLS extension/OCSP.\n\nChrome requires 2+ SCTs per cert (from different logs). Let's Encrypt embeds SCTs in all issued certs.", "mental_model" => "CT logging proof -- SCT, signed timestamp from log, Chrome requires 2+.", "purpose" => ["proof of ct log inclusion in x.509"], "good_for" => ["public TLS cert compliance", "chrome ct policy"], "avoid_for" => ["private CA (not required)"], "pros" => ["chrome mandatory", "ct log proof", "misissuance detection"], "cons" => ["log operator trust required"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Structural; log signature ECDSA.", "post_quantum_status" => 1, "example" => ["scenario" => "Let's Encrypt cert SCTs", "input" => ["log" => "Google Argon + Cloudflare Nimbus"], "output" => ["scts" => "2 embedded SCTs"]], "flow" => ["CA gets SCTs from CT logs", "embeds as extension or TLS ext"], "related" => ["ct", "precert-poison", "x509v3"]],
        ["algo" => 724, "uuid" => "13552e", "name" => "tls-features", "type" => "pki", "status" => "active", "title" => "TLS Features", "description_md" => "TLS Features (RFC 7633) is an extension that signals which TLS extensions the cert server must support. id-pe-tlsfeature with status_request OID mandates OCSP stapling.\n\nCAs like Let's Encrypt can include TLS Features to require stapling, preventing OCSP downgrade.", "mental_model" => "Mandate TLS extensions in cert -- TLS Features, OCSP stapling required.", "purpose" => ["require specific tls extensions in cert"], "good_for" => ["mandating ocsp stapling", "preventing downgrade"], "avoid_for" => ["servers without OCSP stapling support"], "pros" => ["rfc 7633", "prevents OCSP downgrade", "CA-mandated stapling"], "cons" => ["server must support required features"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Structural extension.", "post_quantum_status" => 1, "example" => ["scenario" => "Let's Encrypt must-staple cert", "input" => ["feature" => "status_request (OCSP stapling)"], "output" => ["tlsFeatures" => "status_request"]], "flow" => ["embed id-pe-tlsfeature", "status_request OID = OCSP stapling required"], "related" => ["ocsp-stapling", "ocsp", "x509v3"]],
        ["algo" => 725, "uuid" => "061066", "name" => "signed-timestamp", "type" => "pki", "status" => "active", "title" => "Signed Timestamp", "description_md" => "Signed Timestamp (RFC 3161, used in CAdES/XAdES) is a hash of a document or signature signed by a trusted timestamp authority. Proves a document existed at a specific time.\n\nTimestamps are used in code signing (Authenticode) and long-term signature archival (CAdES/XAdES).", "mental_model" => "Trusted time proof -- RFC 3161, TSA-signed hash, code signing standard.", "purpose" => ["trusted timestamping for document/signature"], "good_for" => ["authenticode code signing timestamp", "long-term signature archival", "legal timestamps"], "avoid_for" => ["simple logging (NTP sufficient)"], "pros" => ["rfc 3161 standard", "authenticode standard", "long-term validity"], "cons" => ["TSA trust required"], "difficulty" => 2, "security" => 4, "quantum_impact" => "TSA RSA/ECDSA; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Authenticode code signing timestamp", "input" => ["hash" => "SHA-256 of code", "tsa" => "timestamp authority"], "output" => ["timestamp" => "RFC 3161 signed timestamp"]], "flow" => ["hash content", "TimeStampReq to TSA", "TSA: signed TimeStampResp"], "related" => ["tsp", "cades", "cms", "x509v3"]],
        ["algo" => 726, "uuid" => "a64e6f", "name" => "tsp", "type" => "pki", "status" => "active", "title" => "TSP", "description_md" => "TSP (Time-Stamp Protocol, RFC 3161) is the protocol for requesting and receiving signed timestamps from a Timestamp Authority. A TSA issues signed TimeStampToken objects.\n\nTSP is the underlying protocol for all RFC 3161 timestamps. Authenticode, Adobe, and DocuSign use TSP.", "mental_model" => "Timestamp protocol -- TSP RFC 3161, TSA issues signed time tokens.", "purpose" => ["timestamp authority protocol (rfc 3161)"], "good_for" => ["code signing timestamps", "pdf signing timestamps", "long-term archival"], "avoid_for" => ["real-time time sync (ntp/ptp)"], "pros" => ["rfc 3161 standard", "universal support", "authenticode/pdf standard"], "cons" => ["TSA availability dependency"], "difficulty" => 2, "security" => 4, "quantum_impact" => "RSA/ECDSA signed; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "TSP timestamp token", "input" => ["hash" => "SHA-256 digest", "policy" => "1.2.3"], "output" => ["token" => "RFC 3161 TimeStampToken"]], "flow" => ["TimeStampReq: hash + nonce", "TSA verifies + signs TimeStampToken", "token embedded in signature"], "related" => ["signed-timestamp", "cades", "pades", "cms"]],
        ["algo" => 727, "uuid" => "c2ffe8", "name" => "cades", "type" => "pki", "status" => "active", "title" => "CAdES", "description_md" => "CAdES (CMS Advanced Electronic Signatures, ETSI EN 319 122) extends CMS for long-term signatures. Defines profiles: CAdES-B (basic), CAdES-T (timestamp), CAdES-LT (revocation), CAdES-LTA (archive).\n\nCAdES is the EU eIDAS standard for advanced signatures. Commonly used in government PKI.", "mental_model" => "Long-term CMS signature -- CAdES ETSI, timestamped, revocation-embedded, EU eIDAS.", "purpose" => ["long-term cms signatures (eu eidas)"], "good_for" => ["eu eidas compliance", "government signing", "long-term archival"], "avoid_for" => ["web signatures (jws)", "simple code signing (cms)"], "pros" => ["etsi standard", "eu eidas", "long-term validity", "multi-profile"], "cons" => ["complex", "EU-focused"], "difficulty" => 3, "security" => 5, "quantum_impact" => "RSA/ECDSA; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "CAdES-LTA long-term signature", "input" => ["doc" => "document", "cert" => "signing cert"], "output" => ["sig" => "CAdES-LTA with timestamp + revocation"]], "flow" => ["sign CMS SignedData (CAdES-B)", "add timestamp (CAdES-T)", "embed revocation data (CAdES-LT)", "archive timestamp (CAdES-LTA)"], "related" => ["cms", "tsp", "signed-timestamp", "pades"]],
        ["algo" => 728, "uuid" => "84a82e", "name" => "pades", "type" => "pki", "status" => "active", "title" => "PAdES", "description_md" => "PAdES (PDF Advanced Electronic Signatures, ETSI EN 319 102) defines standards for long-term PDF digital signatures. Used in PDF/A-2 and ISO 32000-2 (PDF 2.0) for eIDAS compliance.\n\nPAdES is Adobe Acrobat's signature standard for legally binding PDFs.", "mental_model" => "Long-term PDF signature -- PAdES ETSI, Adobe PDF, EU eIDAS compliance.", "purpose" => ["long-term pdf digital signatures (eu eidas)"], "good_for" => ["pdf legal signatures", "eu eidas compliance", "adobe acrobat signing"], "avoid_for" => ["non-pdf documents (CAdES)"], "pros" => ["etsi standard", "adobe standard", "eu eidas", "pdf 2.0 integrated"], "cons" => ["pdf-specific"], "difficulty" => 3, "security" => 5, "quantum_impact" => "RSA/ECDSA; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "EU contract PDF signing", "input" => ["pdf" => "contract.pdf", "cert" => "qualified cert"], "output" => ["signed_pdf" => "PAdES-LTA"]], "flow" => ["embed signature in PDF structure", "add timestamp + revocation", "archive timestamp for long-term"], "related" => ["cades", "xades", "tsp", "cms"]],
        ["algo" => 729, "uuid" => "32fd9d", "name" => "xades", "type" => "pki", "status" => "active", "title" => "XAdES", "description_md" => "XAdES (XML Advanced Electronic Signatures, ETSI EN 319 132) extends XMLDSig for long-term signatures. Profiles: XAdES-B, XAdES-T, XAdES-LT, XAdES-LTA.\n\nXAdES is used in EU VAT (e-invoicing), government document signing, and B2B XML transactions.", "mental_model" => "Long-term XML signature -- XAdES ETSI, XMLDSig extension, EU eIDAS.", "purpose" => ["long-term xml signatures (eu eidas)"], "good_for" => ["eu e-invoicing", "xml government signing", "b2b xml transactions"], "avoid_for" => ["non-xml (cades/pades)"], "pros" => ["etsi standard", "eu eidas", "xmldsig extension"], "cons" => ["xml-specific", "verbose"], "difficulty" => 3, "security" => 5, "quantum_impact" => "RSA/ECDSA; classical.", "post_quantum_status" => 1, "example" => ["scenario" => "EU VAT e-invoice XML signing", "input" => ["xml" => "invoice.xml", "cert" => "qualified cert"], "output" => ["signed_xml" => "XAdES-LT"]], "flow" => ["XMLDSig + XAdES qualifying properties", "add timestamp + revocation data"], "related" => ["cades", "pades", "cms", "tsp"]],
        ["algo" => 730, "uuid" => "8a9cea", "name" => "asn1-der", "type" => "pki", "status" => "active", "title" => "ASN.1 DER", "description_md" => "ASN.1 DER (Distinguished Encoding Rules) is the canonical binary encoding used in X.509, TLS, PKCS, CMS, LDAP, and virtually all PKI formats. DER ensures a unique binary encoding for any ASN.1 structure.\n\nDER is the format for X.509 certs (.der, .cer), PKCS#12 (.p12/.pfx), PKCS#8 private keys, and all TLS wire formats.", "mental_model" => "Canonical PKI binary encoding -- ASN.1 DER, X.509/TLS/PKCS standard binary format.", "purpose" => ["canonical asn.1 binary encoding (pki standard)"], "good_for" => ["x.509 cert encoding", "tls wire format", "pkcs#12 containers", "pkcs#8 keys"], "avoid_for" => ["human-readable (use PEM/JSON)"], "pros" => ["canonical unique", "universal pki standard", "compact", "TLS wire format"], "cons" => ["not human-readable"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Encoding format; used for PQ cert encoding.", "post_quantum_status" => 1, "example" => ["scenario" => "X.509 cert DER encoding", "input" => ["cert" => "x509 structure"], "output" => ["der" => "binary DER bytes"]], "flow" => ["ASN.1 structure", "TLV encoding (DER rules)", "canonical binary result"], "related" => ["asn1-ber", "asn1-cer", "x509v3", "cms"]],
        ["algo" => 732, "uuid" => "fa67c7", "name" => "asn1-cer", "type" => "pki", "status" => "active", "title" => "ASN.1 CER", "description_md" => "ASN.1 CER (Canonical Encoding Rules) is a subset of BER with specific canonicalization rules, used in S/MIME and some PKI applications. Similar to DER but with different indefinite-length rules.\n\nCER is rarely used in new applications; DER is preferred for PKI.", "mental_model" => "Canonical BER subset -- ASN.1 CER, S/MIME historical use.", "purpose" => ["canonical ber encoding (asn.1 subset)"], "good_for" => ["s/mime legacy", "historical asn.1 applications"], "avoid_for" => ["new applications (use DER)"], "pros" => ["asn.1 standard", "canonical"], "cons" => ["rarely used", "DER preferred"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Encoding format.", "post_quantum_status" => 1, "example" => ["scenario" => "CER encoding", "input" => ["asn1" => "structure"], "output" => ["cer" => "CER bytes"]], "flow" => ["BER + CER canonicalization rules"], "related" => ["asn1-der", "asn1-ber", "x509v3"]],
        ["algo" => 733, "uuid" => "956d1b", "name" => "asn1-per", "type" => "pki", "status" => "active", "title" => "ASN.1 PER", "description_md" => "ASN.1 PER (Packed Encoding Rules) is a compact binary encoding optimized for bandwidth efficiency. Used in 3G/4G/5G radio protocols (NGAP, RRC), avionics (ACARS), and SNMP.\n\nPER is not used in PKI but is standard in telecom and avionics ASN.1 protocols.", "mental_model" => "Compact ASN.1 for telecom/radio -- PER, 3G/4G/5G NGAP/RRC standard.", "purpose" => ["bandwidth-efficient asn.1 encoding (telecom)"], "good_for" => ["3gpp 5g ngap/rrc", "avionics protocols", "snmp"], "avoid_for" => ["pki (use DER)"], "pros" => ["very compact", "telecom standard", "3gpp standard"], "cons" => ["telecom-specific", "not pki"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Encoding format.", "post_quantum_status" => 1, "example" => ["scenario" => "5G NGAP PER message", "input" => ["msg" => "ASN.1 NGAP structure"], "output" => ["per" => "compact binary"]], "flow" => ["ASN.1 structure", "PER alignment + packing rules", "compact binary"], "related" => ["asn1-der", "asn1-oer"]],
        ["algo" => 734, "uuid" => "aa6c2e", "name" => "asn1-oer", "type" => "pki", "status" => "active", "title" => "ASN.1 OER", "description_md" => "ASN.1 OER (Octet Encoding Rules) is a compact, fast encoding designed for machine-to-machine protocols. Easier to implement than PER with similar compactness.\n\nOER is used in V2X (vehicle-to-vehicle) communications (IEEE 1609.2) and SCMS (Security Credential Management System).", "mental_model" => "V2X / M2M compact ASN.1 -- OER, IEEE 1609.2, simpler than PER.", "purpose" => ["fast compact asn.1 for m2m/v2x"], "good_for" => ["v2x (ieee 1609.2)", "scms vehicle security", "m2m protocols"], "avoid_for" => ["pki (der)", "telecom (per)"], "pros" => ["compact", "simpler than PER", "v2x standard"], "cons" => ["niche application"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Encoding format.", "post_quantum_status" => 1, "example" => ["scenario" => "V2X IEEE 1609.2 message", "input" => ["msg" => "ASN.1 V2X structure"], "output" => ["oer" => "compact OER bytes"]], "flow" => ["ASN.1 structure", "OER encoding", "V2X transmission"], "related" => ["asn1-per", "asn1-der"]],
        ["algo" => 735, "uuid" => "238001", "name" => "asn1-xer", "type" => "pki", "status" => "active", "title" => "ASN.1 XER", "description_md" => "ASN.1 XER (XML Encoding Rules) serializes ASN.1 structures to XML. Provides human-readable ASN.1 in XML format. Used in LDAP, Directory Services, and some PKI management protocols.\n\nXER is useful for debugging and interoperability testing of ASN.1 protocols.", "mental_model" => "XML ASN.1 encoding -- XER, human-readable ASN.1, LDAP/debug use.", "purpose" => ["xml encoding of asn.1 structures"], "good_for" => ["asn.1 debugging", "ldap xml", "interoperability testing"], "avoid_for" => ["production pki (der)", "bandwidth-sensitive (per/oer)"], "pros" => ["human-readable", "xml tools apply", "debug-friendly"], "cons" => ["verbose", "not for production pki"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Encoding format.", "post_quantum_status" => 1, "example" => ["scenario" => "ASN.1 XER debug", "input" => ["asn1" => "structure"], "output" => ["xer" => "<structure>...</structure>"]], "flow" => ["ASN.1 structure", "XER element encoding", "XML output"], "related" => ["asn1-der", "asn1-cer", "x509v3"]],
    ],
